    """
    Convert a cell number to its corresponding coordinates in the maze.
    Cells 1 to n are in row 0, cells n+1 to 2n are in row 1.
    Returns (row, col) tuple.
    """
    if cell_num <= n:
        return (0, cell_num - 1)
    else:
        return (1, cell_num - n - 1)

def coords_to_cell(row, col, n):
    """
    Convert coordinates (row, column) in the maze to a cell number.
    Row 0 cells are numbered 1 to n, row 1 cells are numbered n+1 to 2n.
    """
    if row == 0:
        return col + 1
    else:
        return n + col + 1

def get_neighbors(cell_num, n, maze):
    """
    Retrieve all valid neighboring cells of a given cell in the maze.
    Returns a list of valid neighbor cell numbers.
    """
    row, col = cell_to_coords(cell_num, n)
    neighbors = []

