    return neighbors

def is_reachable(start, end, n, maze):
    """
    Check if the destination cell is reachable from the starting cell in the maze.
    Uses BFS to explore the maze.
    Returns True if reachable, False otherwise.
    """
    if start == end:
        return True

    visited = set()
    queue = [start]
    visited.add(start)

    while queue:
        current = queue.pop(0)
        if current == end:
            return True
        for neighbor in get_neighbors(current, n, maze):
            if neighbor not in visited:
                visited.add(neighbor)
                queue.append(neighbor)

    return False

def find_shortest_path(start, end, n, maze):
    """
    Find the shortest path from the starting cell to the destination cell in the maze.
    Uses BFS to compute the shortest path length.
    Returns the path length or -1 if not reachable.
    """
    if start == end:
        return 0

    visited = {start: 0}
    queue = [start]

    while queue:
        current = queue.pop(0)
        current_dist = visited[current]

